mapper.select:
SELECT CO_ID, FILE_ID, FILE_NM, FILE_PATH, FILE_TP, FILE_SZ, CRE_USR_ID, CRE_DT, UPD_USR_ID, UPD_DT FROM COM_FILE WHERE 1 = 1
AND CO_ID = #{coId}
AND FILE_ID = #{fileId}
AND FILE_PATH = #{filePath}
LIMIT 1

